mapper.select:
SELECT c.check_out_record_id AS id, u.customer_name AS customerName, CASE WHEN c.type = '0' THEN '正常退住' WHEN c.type = '1' THEN '死亡退住' WHEN c.type = '2' THEN '保留床位' ELSE '未知状态' END AS checkOutType, c.reason AS checkOutReason, c.check_out_date AS checkOutDate, CASE WHEN c.status = '0' THEN '通过' WHEN c.status = '1' THEN '不通过' WHEN c.status = '2' THEN '已提交' WHEN c.status = '3' THEN '未提交' WHEN c.status = '4' THEN '已撤销' ELSE '未知' END AS approvalStatus FROM check_out_record c LEFT JOIN customer u ON c.customer_id = u.customer_id WHERE c.user_id = #{userId} AND c.del_flag = '0'
AND u.customer_name LIKE CONCAT('%', #{customerName}, '%')
order by c.check_out_record_id DESC LIMIT #{pageStart}, #{pageSize}

